import fs from "node:fs";
import { getLogger, setupLogger } from "../src/lib/logger.js";
import { parseSecrets } from "../src/parse-secrets.js";

void (async () => {
	await setupLogger();
	const logger = getLogger(["bao", "action", "parse-secrets"]);
	try {
		parseSecrets(process.env, fs.appendFileSync, (msg) =>
			logger.info("{msg}", { msg }),
		);
	} catch (err) {
		logger.fatal("::error::{message}", { message: (err as Error).message });
		process.exit(1);
	}
})();
